            .trim()
            .parse()
            .map_err(|_| format!("line {}: invalid number", line_no))?;

        out.insert(key.to_string(), value);
",
      "replace": "        let raw_value = parts[1].trim();
        let value: u32 = raw_value
            .parse()
            .map_err(|_| format!("line {}: invalid number '{}'", line_no, raw_value))?;

        if out.contains_key(key) {
            return Err(format!("line {}: duplicate key '{}'", line_no, key));
        }

        out.insert(key.to_string(), value);
"
