    "src/lib.rs": "use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub day: &'static str,
    pub rep: &'static str,
    pub region: &'static str,
    pub amount: i32,
    pub refunded: bool,
}

pub fn daily_region_report(sales: &[Sale]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();
    let mut counts: BTreeMap<&str, usize> = BTreeMap::new();

    for sale in sales {
        if sale.amount <= 0 {
            continue;
        }
        *totals.entry(sale.day).or_insert(0) += sale.amount;
        *counts.entry(sale.day).or_insert(0) += 1;
    }

    let mut lines = Vec::new();
    for (day, total) in totals {
        let count = counts.get(day).copied().unwrap_or(0);
        lines.push(format!("{}: total={}, orders={}", day, total, count));
    }

    if lines.is_empty() {
        "no sales".to_string()
    } else {
        lines.join("\n")
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn sample_sales() -> Vec<Sale> {
        vec![
            Sale { day: "2024-05-01", rep: "Ana", region: "east", amount: 100, refunded: false },
            Sale { day: "2024-05-01", rep: "Ben", region: "west", amount: 70, refunded: false },
            Sale { day: "2024-05-01", rep: "Cara", region: "east", amount: 30, refunded: true },
            Sale { day: "2024-05-02", rep: "Ana", region: "east", amount: 90, refunded: false },
            Sale { day: "2024-05-02", rep: "Dan", region: "east", amount: -5, refunded: false },
            Sale { day: "2024-05-02", rep: "Eli", region: "north", amount: 50, refunded: false },
            Sale { day: "2024-05-03", rep: "Fay", region: "west", amount: 40, refunded: true },
        ]
    }

    #[test]
    fn groups_by_day_and_region_and_skips_refunds_and_non_positive() {
        let out = daily_region_report(&sample_sales());
        let expected = "2024-05-01 east: total=100, orders=1\n2024-05-01 west: total=70, orders=1\n2024-05-02 east: total=90, orders=1\n2024-05-02 north: total=50, orders=1";
        assert_eq!(out, expected);
    }

    #[test]
    fn returns_no_sales_when_everything_is_filtered_out() {
        let sales = vec![
            Sale { day: "2024-06-01", rep: "A", region: "east", amount: 0, refunded: false },
            Sale { day: "2024-06-01", rep: "B", region: "west", amount: 10, refunded: true },
            Sale { day: "2024-06-02", rep: "C", region: "north", amount: -2, refunded: false },
        ];
        assert_eq!(daily_region_report(&sales), "no sales");
    }
}
