#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub team: String,
    pub solved: u32,
    pub penalty: u32,
    pub last_submit: u32,
}

pub fn leaderboard(entries: &[Entry]) -> Vec<String> {
    let mut by_team: HashMap<String, Entry> = HashMap::new();

    for e in entries {
        by_team.insert(e.team.clone(), e.clone());
    }

    let mut rows: Vec<Entry> = by_team.into_values().collect();
    rows.sort_by(|a, b| {
        a.solved
            .cmp(&b.solved)
            .then(a.penalty.cmp(&b.penalty))
            .then(a.last_submit.cmp(&b.last_submit))
            .then(a.team.cmp(&b.team))
    });

    rows.into_iter()
        .enumerate()
        .map(|(i, e)| format!("{}. {}", i + 1, e.team))
        .collect()
}

