    "src/lib.rs": "#[derive(Debug, PartialEq, Eq)]
pub struct Settings {
    pub host: String,
    pub port: u16,
    pub secure: bool,
}

pub fn parse_settings(input: &str) -> Result<Settings, String> {
    let mut host = None;
    let mut port = None;
    let mut secure = false;

    for raw in input.lines() {
        let line = raw.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }

        let (key, value) = line
            .split_once('=')
            .ok_or_else(|| format!("invalid line: {}", line))?;

        match key.trim() {
            "host" => host = Some(value.trim().to_string()),
            "port" => {
                port = Some(value.trim().parse::<u16>().map_err(|_| "invalid port".to_string())?)
            }
            "secure" => secure = value.trim() == "true",
            _ => return Err(format!("unknown key: {}", key.trim())),
        }
    }

    Ok(Settings {
        host: host.unwrap_or_default(),
        port: port.unwrap_or(80),
        secure,
    })
}

