    pub month: u8,
    pub amount: i32,
    pub refunded: bool,
}

pub fn team_monthly_report(sales: &[Sale], month: u8) -> Vec<String> {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();

    for sale in sales {
        if sale.month != month {
            continue;
        }
        let entry = totals.entry(sale.team).or_insert(0);
        *entry += sale.amount;
    }

    let mut lines = Vec::new();
    let mut grand_total = 0;

    for (team, total) in totals {
        grand_total += total;
        lines.push(format!("{}: {}", team, total));
    }

    lines.push(format!("TOTAL: {}", grand_total));
    lines
}

