pub fn apply_event(status: Status, event: Event) -> Status {
    match (status, event) {
        (Status::Todo, Event::Start) => Status::InProgress,
        (Status::InProgress, Event::Block) => Status::Blocked,
        (Status::Blocked, Event::Unblock) => Status::Todo,
