pub enum Event {
    Open,
    Ack,
    Snooze(u8),
    Resolve,
    Escalate(Severity),
}

pub fn next_action(event: Event, pending_followup: bool) -> &'static str {
    match event {
        Event::Open => {
            if pending_followup {
                "queue"
            } else {
                "notify"
            }
        }
        Event::Ack => "notify",
        Event::Snooze(minutes) => {
            if minutes <= 30 {
                "queue"
            } else {
                "archive"
            }
        }
        Event::Resolve => {
            if pending_followup {
                "close"
            } else {
                "archive"
            }
        }
        Event::Escalate(level) => match level {
            Severity::Low => "notify",
            Severity::Medium => "page",
            Severity::High => "queue",
        },
    }
}

