    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub enum TaskState {
    Todo,
    InProgress { blocked: bool },
    Done { verified: bool },
    Archived,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Action {
    Start,
    Block,
    Unblock,
    Finish,
    Verify,
    Archive,
    Restore,
}

pub fn apply_action(state: TaskState, action: Action) -> TaskState {
    match (state, action) {
        (TaskState::Todo, Action::Start) => TaskState::InProgress { blocked: false },
        (TaskState::InProgress { .. }, Action::Block) => TaskState::InProgress { blocked: true },
        (TaskState::InProgress { .. }, Action::Unblock) => TaskState::InProgress { blocked: false },
        (TaskState::InProgress { blocked: false }, Action::Finish) => TaskState::Done { verified: true },
        (TaskState::Done { .. }, Action::Verify) => TaskState::Done { verified: false },
        (TaskState::Done { .. }, Action::Archive) => TaskState::Archived,
        (TaskState::Archived, Action::Restore) => TaskState::Done { verified: true },
        (s, _) => s,
    }
}

pub fn apply_actions(mut state: TaskState, actions: &[Action]) -> TaskState {
    for action in actions {
        state = apply_action(state, action.clone());
    }
    state
}

