pub struct Config {
    pub timeout_ms: u64,
    pub retries: u8,
    pub enable_cache: bool,
    pub tags: Vec<&'static str>,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub timeout_ms: Option<u64>,
    pub retries: Option<u8>,
    pub enable_cache: Option<bool>,
    pub tags: Option<Vec<&'static str>>,
}

pub fn merge_config(
    defaults: &Config,
    file: Option<&PartialConfig>,
    env: Option<&PartialConfig>,
) -> Config {
    let mut merged = defaults.clone();

    if let Some(file_cfg) = file {
        if let Some(timeout_ms) = file_cfg.timeout_ms {
            merged.timeout_ms = timeout_ms;
        }
        if let Some(retries) = file_cfg.retries {
            merged.retries = retries;
        }
        if file_cfg.enable_cache.unwrap_or(false) {
            merged.enable_cache = true;
        }
        if let Some(tags) = &file_cfg.tags {
            merged.tags = tags.clone();
        }
    }

    if let Some(env_cfg) = env {
        if let Some(timeout_ms) = env_cfg.timeout_ms {
            merged.timeout_ms = timeout_ms;
        }
        if let Some(retries) = env_cfg.retries {
            merged.retries = retries;
        }
        if let Some(enable_cache) = env_cfg.enable_cache {
            merged.enable_cache = enable_cache;
        }
        if let Some(tags) = &env_cfg.tags {
            merged.tags.extend(tags.iter().copied());
        }
    }

    merged
}

