pub struct Booking {
    pub start: u32,
    pub end: u32,
}

impl Booking {
    pub fn new(start: u32, end: u32) -> Self {
        Self { start, end }
    }
}

pub fn can_book(existing: &[Booking], candidate: Booking) -> bool {
    if candidate.start >= candidate.end {
        return false;
    }

    for slot in existing {
        if candidate.start <= slot.end && slot.start <= candidate.end {
            return false;
        }
    }

    true
}

