    pub name: &'static str,
    pub points: u32,
    pub wins: u32,
    pub goal_diff: i32,
}

pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut rows = players.to_vec();
    rows.sort_by(|a, b| {
        a.points
            .cmp(&b.points)
            .then(a.wins.cmp(&b.wins))
            .then(a.goal_diff.cmp(&b.goal_diff))
            .then(a.name.cmp(&b.name))
    });

    rows
        .into_iter()
        .enumerate()
        .map(|(i, p)| format!("{}. {} [{}p, {}w, gd {}]", i + 1, p.name, p.points, p.wins, p.goal_diff))
