    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub wins: u32,
    pub draws: u32,
    pub losses: u32,
    pub goals_for: i32,
    pub goals_against: i32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedPlayer {
    pub rank: usize,
    pub name: &'static str,
    pub points: u32,
    pub goal_diff: i32,
    pub goals_for: i32,
}

fn points(p: &Player) -> u32 {
    p.wins * 3 + p.draws
}

fn goal_diff(p: &Player) -> i32 {
    p.goals_for - p.goals_against
}

pub fn leaderboard(players: &[Player]) -> Vec<RankedPlayer> {
    let mut rows: Vec<&Player> = players.iter().collect();
    rows.sort_by(|a, b| {
        points(a)
            .cmp(&points(b))
            .then_with(|| goal_diff(a).cmp(&goal_diff(b)))
            .then_with(|| a.goals_for.cmp(&b.goals_for))
            .then_with(|| a.name.cmp(b.name))
    });

    rows.into_iter()
        .enumerate()
        .map(|(i, p)| RankedPlayer {
            rank: i + 1,
            name: p.name,
            points: points(p),
            goal_diff: goal_diff(p),
            goals_for: p.goals_for,
        })
        .collect()
}

