            Resource::Document { archived: true } => "deny",
            Resource::Document { archived: false } => match role {
                Role::Admin => "allow",
                _ => "deny",
            },
            Resource::AuditLog => "deny",
            Resource::Billing => "deny",
        },
        Action::Export => match resource {
            Resource::Document { archived: true } => "allow",
            Resource::Document { archived: false } => "allow",
            Resource::AuditLog => "deny",
            Resource::Billing => match role {
