            .unwrap_or_else(|| defaults.host.clone()),
        port: env.port.or(profile.port).unwrap_or(defaults.port),
        use_tls: profile.use_tls.unwrap_or(env.use_tls.unwrap_or(defaults.use_tls)),
        timeout_ms: profile.timeout_ms.unwrap_or(defaults.timeout_ms),
