            Player { name: "Bea", points: 12, wins: 5, penalties: 1 },
            Player { name: "Dan", points: 12, wins: 5, penalties: 1 },
        ];

        let board = leaderboard(&players);
        let names: Vec<&str> = board
            .iter()
            .map(|line| line.split_once(". ").unwrap().1.split_once(" [").unwrap().0)
            .collect();

