#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Status {
    Pending,
    Shipped,
    Cancelled,
}

#[derive(Clone, Debug)]
pub struct Order<'a> {
    pub region: &'a str,
    pub amount_cents: u32,
    pub status: Status,
}

pub fn build_region_report(orders: &[Order<'_>]) -> String {
    let mut totals: BTreeMap<&str, (u32, u32)> = BTreeMap::new();

    for order in orders {
        let entry = totals.entry(order.region).or_insert((0, 0));
        entry.0 += 1;
        entry.1 += order.amount_cents;
    }

    let mut rows: Vec<_> = totals.into_iter().collect();
    rows.sort_by(|a, b| a.0.cmp(b.0));

    rows.into_iter()
        .map(|(region, (count, cents))| format!("{}|{}|{}", region, count, cents))
        .collect::<Vec<_>>()
        .join("\n")
}

