    pub region: &'static str,
    pub customer: &'static str,
    pub amount_cents: u32,
    pub shipped: bool,
    pub cancelled: bool,
}

pub fn build_region_report(orders: &[Order]) -> String {
    let mut totals: BTreeMap<&str, (u32, u32)> = BTreeMap::new();

    for order in orders {
        if !order.shipped {
            continue;
        }

        let entry = totals.entry(order.region).or_insert((0, 0));
        entry.0 += order.amount_cents;
        entry.1 += 1;
    }

    let mut rows: Vec<_> = totals.into_iter().collect();
    rows.sort_by(|a, b| a.0.cmp(b.0));

    rows.into_iter()
        .map(|(region, (amount, customers))| format!("{}:${:.2}:{}", region, amount as f64 / 100.0, customers))
