    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Event {
    Created { urgent: bool },
    Updated { fields: usize, dry_run: bool },
    Deleted { soft: bool },
    Archived,
}

pub fn route(event: Event) -> &'static str {
    match event {
        Event::Created { .. } => "create",
        Event::Updated { dry_run, .. } => {
            if dry_run {
                "update"
            } else {
                "preview"
            }
        }
        Event::Deleted { .. } => "delete",
        Event::Archived => "delete",
    }
}

pub fn classify(event: Event) -> &'static str {
    match event {
        Event::Created { urgent } => {
            if urgent {
                "normal"
            } else {
                "priority"
            }
        }
        Event::Updated { fields, .. } => {
            if fields == 0 {
                "delta"
            } else {
                "noop"
            }
        }
        Event::Deleted { soft } => {
            if soft {
                "destructive"
            } else {
                "recoverable"
            }
        }
        Event::Archived => "destructive",
    }
}

pub fn describe(event: Event) -> String {
    match event {
        Event::Created { urgent } => format!("{} create", classify(Event::Created { urgent })),
        Event::Updated { fields, dry_run } => {
            let route_name = route(Event::Updated { fields, dry_run });
            format!("{} {}", classify(Event::Updated { fields, dry_run }), route_name)
        }
        Event::Deleted { soft } => format!("{} {}", route(Event::Deleted { soft }), classify(Event::Deleted { soft })),
        Event::Archived => format!("{} {}", route(Event::Archived), classify(Event::Archived)),
    }
}

