        assert_eq!(route(Event::Created { urgent: false }), "create");
        assert_eq!(route(Event::Updated { fields: 2, dry_run: true }), "preview");
        assert_eq!(route(Event::Updated { fields: 2, dry_run: false }), "update");
        assert_eq!(route(Event::Deleted { soft: true }), "delete");
        assert_eq!(route(Event::Archived), "archive");
    }

    #[test]
    fn classifications_reflect_variant_details() {
        assert_eq!(classify(Event::Created { urgent: true }), "priority");
        assert_eq!(classify(Event::Created { urgent: false }), "normal");
        assert_eq!(classify(Event::Updated { fields: 0, dry_run: false }), "noop");
        assert_eq!(classify(Event::Updated { fields: 3, dry_run: true }), "delta");
        assert_eq!(classify(Event::Deleted { soft: true }), "recoverable");
        assert_eq!(classify(Event::Deleted { soft: false }), "destructive");
        assert_eq!(classify(Event::Archived), "retained");
    }

    #[test]
    fn description_combines_classification_and_route() {
        assert_eq!(describe(Event::Created { urgent: true }), "priority create");
        assert_eq!(describe(Event::Updated { fields: 0, dry_run: true }), "noop preview");
        assert_eq!(describe(Event::Updated { fields: 2, dry_run: false }), "delta update");
        assert_eq!(describe(Event::Deleted { soft: true }), "recoverable delete");
        assert_eq!(describe(Event::Archived), "retained archive");
    }
