    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub wins: u32,
    pub draws: u32,
    pub losses: u32,
    pub goals_for: i32,
    pub goals_against: i32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedPlayer {
    pub rank: usize,
    pub name: &'static str,
    pub points: i32,
    pub goal_diff: i32,
    pub played: u32,
}

pub fn rank_players(players: &[Player]) -> Vec<RankedPlayer> {
    let mut rows: Vec<RankedPlayer> = players
        .iter()
        .enumerate()
        .map(|(idx, p)| RankedPlayer {
            rank: idx + 1,
            name: p.name,
            points: (p.wins as i32) * 2 + p.draws as i32,
            goal_diff: p.goals_for - p.goals_against,
            played: p.wins + p.draws + p.losses,
        })
        .collect();

    rows.sort_by(|a, b| {
        a.points
            .cmp(&b.points)
            .then(a.goal_diff.cmp(&b.goal_diff))
            .then(a.played.cmp(&b.played))
            .then(a.name.cmp(&b.name))
    });

    for (idx, row) in rows.iter_mut().enumerate() {
        row.rank = idx + 1;
    }

    rows
}

