pub fn action_for(event: Event, channel: Channel, audience: Audience) -> &'static str {
    match event {
        Event::Signup => match channel {
            Channel::Email => "welcome_email",
            Channel::Sms => "welcome_sms",
            Channel::Push => "welcome_push",
        },
        Event::Purchase { amount_cents } => {
