pub struct Config {
    pub host: String,
    pub port: u16,
    pub use_tls: bool,
    pub timeout_ms: u64,
    pub tags: Vec<String>,
    pub header: Option<String>,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
    pub timeout_ms: Option<u64>,
    pub tags: Option<Vec<String>>,
    pub clear_tags: bool,
    pub header: Option<Option<String>>,
}

pub fn merge_config(
    defaults: &Config,
    env: &PartialConfig,
    cli: &PartialConfig,
) -> Config {
    let mut merged = defaults.clone();

    if let Some(host) = &env.host {
        merged.host = host.clone();
    }
    if let Some(host) = &cli.host {
        merged.host = host.clone();
    }

    if let Some(port) = cli.port {
        merged.port = port;
    } else if let Some(port) = env.port {
        merged.port = port;
    }

    if let Some(use_tls) = env.use_tls {
        merged.use_tls = use_tls;
    }
    if let Some(use_tls) = cli.use_tls {
        merged.use_tls = use_tls;
    }

    if let Some(timeout_ms) = cli.timeout_ms {
        merged.timeout_ms = timeout_ms;
    } else if let Some(timeout_ms) = env.timeout_ms {
        merged.timeout_ms = timeout_ms;
    }

    if let Some(tags) = &env.tags {
        merged.tags = tags.clone();
    }
    if let Some(tags) = &cli.tags {
        merged.tags.extend(tags.clone());
    }
    if cli.clear_tags {
        merged.tags.clear();
    }

    if let Some(header) = &env.header {
        merged.header = header.clone();
    }
    if let Some(header) = &cli.header {
        merged.header = header.clone();
    }

    merged
}

