        assert_eq!(apply_events(&[Event::Start, Event::Block, Event::Close]), Status::Closed);
    }

    #[test]
    fn reopen_goes_back_to_in_progress() {
        assert_eq!(
            apply_events(&[Event::Start, Event::Close, Event::Reopen]),
            Status::InProgress
