}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Event {
    Welcome,
    PasswordReset,
    BillingFailure,
    WeeklyDigest,
}

pub fn delivery_action(channel: Channel, priority: Priority, event: Event) -> &'static str {
    match channel {
