        },
        Channel::Push => match priority {
            Priority::High => "send_immediately",
            Priority::Normal => "drop",
            Priority::Low => "queue_email",
        },
        Channel::Webhook => match event {
            Event::Welcome => "send_immediately",
            Event::PasswordReset => "send_immediately",
            Event::BillingFailure => "queue_email",
            Event::WeeklyDigest => "send_immediately",
