    pub points: u32,
    pub wins: u32,
    pub goal_diff: i32,
}

pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut ordered = players.to_vec();
    ordered.sort_by(|a, b| {
        a.points
            .cmp(&b.points)
            .then_with(|| a.wins.cmp(&b.wins))
            .then_with(|| a.goal_diff.cmp(&b.goal_diff))
            .then_with(|| a.name.cmp(b.name))
    });

    ordered
        .into_iter()
        .enumerate()
        .map(|(idx, p)| format!("{}. {}", idx + 1, p.name))
        .collect()
}

