pub fn build_report(entries: &[Entry]) -> String {
    let mut totals: Vec<(&'static str, u32)> = Vec::new();

    for e in entries {
        match totals.iter_mut().find(|(team, _)| *team == e.team) {
            Some((_, total)) => *total += e.minutes,
            None => totals.push((e.team, e.minutes)),
        }
    }

    totals.sort_by(|a, b| a.0.cmp(b.0));

    let mut lines = Vec::new();
    for (team, minutes) in totals {
        let hours = minutes / 60;
        let mins = minutes % 60;
        lines.push(format!("{}: {}h{}m", team, hours, mins));
    }

    lines.join("\n")
}

