#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Event {
    pub team: &'static str,
    pub hours: u32,
    pub billable: bool,
}

pub fn build_report(events: &[Event]) -> String {
    let mut per_team: BTreeMap<&str, (u32, u32)> = BTreeMap::new();

    for event in events {
        let entry = per_team.entry(event.team).or_insert((0, 0));
        if event.billable {
            entry.0 += event.hours;
        }
        entry.1 += 1;
    }

    let mut lines = Vec::new();
    let mut total_billable = 0;
    let mut total_events = 0;

    for (team, (billable_hours, events_count)) in per_team {
        total_billable += billable_hours;
        total_events += events_count;
        lines.push(format!("{}: {}h billable across {} events", team, billable_hours, events_count));
    }

    lines.push(format!("TOTAL: {}h billable across {} events", total_billable, total_events));
    lines.join("\n")
}

