            if opted_in_marketing {
                Action::Send { channel: Channel::Push, urgent: false }
            } else {
                Action::Suppress
            }
        }
        Event::Alert => {
            if low_power_mode {
                Action::Suppress
            } else if user_verified {
                Action::Send { channel: Channel::Email, urgent: true }
            } else {
                Action::Queue { channel: Channel::Sms }
