pub struct Config {
    pub host: String,
    pub port: u16,
    pub use_tls: bool,
    pub timeout_ms: u32,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
    pub timeout_ms: Option<u32>,
}

pub fn merge_config(
    defaults: &Config,
    profile: Option<&PartialConfig>,
    env: Option<&PartialConfig>,
    cli: Option<&PartialConfig>,
) -> Config {
    let mut out = defaults.clone();

    if let Some(p) = profile {
        apply_layer(&mut out, p);
    }
    if let Some(e) = env {
        apply_layer(&mut out, e);
    }
    if let Some(c) = cli {
        apply_layer(&mut out, c);
    }

    out
}

fn apply_layer(out: &mut Config, layer: &PartialConfig) {
    if let Some(host) = &layer.host {
        out.host = host.clone();
    }
    if let Some(port) = layer.port {
        out.port = port;
    }
    if let Some(use_tls) = layer.use_tls {
        out.use_tls = use_tls;
    }
    if let Some(timeout_ms) = layer.timeout_ms {
        out.timeout_ms = timeout_ms;
    }
}

