    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Draft,
    Active,
    Suspended,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Suspend,
    Resume,
    Close,
    Reopen,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::Draft;
    let mut ever_closed = false;

    for event in events {
        status = match (status, *event) {
            (Status::Draft, Event::Submit) => Status::Active,
            (Status::Draft, Event::Close) => {
                ever_closed = true;
                Status::Closed
            }
            (Status::Active, Event::Suspend) => Status::Suspended,
            (Status::Active, Event::Close) => {
                ever_closed = true;
                Status::Closed
            }
            (Status::Suspended, Event::Resume) => Status::Active,
            (Status::Suspended, Event::Close) => {
                ever_closed = true;
                Status::Closed
            }
            (Status::Closed, Event::Reopen) => {
                if ever_closed {
                    Status::Draft
                } else {
                    Status::Closed
                }
            }
            _ => status,
        };
    }

    status
}

