    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Route {
    Home,
    Login { redirect: bool },
    User { id: u32, section: Section },
    Search { query: Option<String>, page: u32 },
    Admin(AdminPage),
    Help,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Section {
    Overview,
    Settings,
    Billing,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum AdminPage {
    Dashboard,
    Users { active_only: bool },
    Audit { severity: Severity },
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Severity {
    Low,
    High,
}

pub fn action_for(route: &Route, is_authenticated: bool, is_admin: bool) -> &'static str {
    match route {
        Route::Home => "render:home",
        Route::Login { redirect } => {
            if *redirect {
                "render:login"
            } else if is_authenticated {
                "redirect:home"
            } else {
                "render:login"
            }
        }
        Route::User { id, section } => {
            if *id == 0 {
                "redirect:home"
            } else {
                match section {
                    Section::Overview => "render:user_overview",
                    Section::Settings => "render:user_overview",
                    Section::Billing => {
                        if is_authenticated {
                            "render:user_billing"
                        } else {
                            "render:user_billing"
                        }
                    }
                }
            }
        }
        Route::Search { query, page } => {
            if *page == 0 {
                "redirect:search"
            } else if query.as_deref().unwrap_or("").is_empty() {
                "render:search_results"
            } else {
                "render:search_results"
            }
        }
        Route::Admin(page) => {
            if !is_admin {
                "render:admin_dashboard"
            } else {
                match page {
                    AdminPage::Dashboard => "render:admin_dashboard",
                    AdminPage::Users { active_only } => {
                        if *active_only {
                            "render:admin_users"
                        } else {
                            "render:admin_users"
                        }
                    }
                    AdminPage::Audit { severity } => match severity {
                        Severity::Low => "render:admin_audit_high",
                        Severity::High => "render:admin_audit_high",
                    },
                }
            }
        }
        Route::Help => "redirect:home",
