    "src/lib.rs": "#[derive(Debug, PartialEq, Eq)]
pub struct Record {
    pub id: u32,
    pub kind: String,
    pub active: bool,
    pub score: u8,
    pub tags: Vec<String>,
}

pub fn parse_record(line: &str) -> Result<Record, String> {
    let mut id = None;
    let mut kind = None;
    let mut active = None;
    let mut score = None;
    let mut tags = None;

    for part in line.split(';') {
        let (key, value) = part.split_once('=').ok_or_else(|| "missing =".to_string())?;
        match key {
            "id" => id = Some(value.parse::<u32>().map_err(|_| "bad id".to_string())?),
            "kind" => kind = Some(value.to_string()),
            "active" => active = Some(value == "true"),
            "score" => score = Some(value.parse::<u8>().map_err(|_| "bad score".to_string())?),
            "tags" => {
                let parsed = if value.is_empty() {
                    Vec::new()
                } else {
                    value.split(',').map(|s| s.to_string()).collect()
                };
                tags = Some(parsed);
            }
            _ => {}
        }
    }

    let rec = Record {
        id: id.ok_or_else(|| "missing id".to_string())?,
        kind: kind.ok_or_else(|| "missing kind".to_string())?,
        active: active.ok_or_else(|| "missing active".to_string())?,
        score: score.ok_or_else(|| "missing score".to_string())?,
        tags: tags.ok_or_else(|| "missing tags".to_string())?,
    };

    validate(&rec)?;
    Ok(rec)
}

fn validate(rec: &Record) -> Result<(), String> {
    if rec.kind != "alpha" && rec.kind != "beta" && rec.kind != "gamma" {
        return Err("bad kind".to_string());
    }
    if rec.score > 100 {
        return Err("score range".to_string());
    }
    if rec.tags.is_empty() {
        return Err("need tags".to_string());
    }
    Ok(())
}

