pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut rows = players.to_vec();
    rows.sort_by(|a, b| {
        a.wins
            .cmp(&b.wins)
            .then_with(|| a.losses.cmp(&b.losses))
            .then_with(|| a.name.cmp(b.name))
    });

    rows.into_iter()
        .enumerate()
        .map(|(i, p)| format!("{}. {} ({}-{})", i + 1, p.name, p.wins, p.losses))
        .collect()
}

