pub struct Sale {
    pub region: &'static str,
    pub month: u8,
    pub amount: i32,
    pub refunded: bool,
}

pub fn summarize(sales: &[Sale]) -> String {
    let mut groups: BTreeMap<&str, (i32, usize, usize)> = BTreeMap::new();

    for sale in sales {
        let entry = groups.entry(sale.region).or_insert((0, 0, 0));
        entry.0 += sale.amount;
        entry.1 += 1;
        if sale.refunded {
            entry.2 += 1;
        }
    }

    let mut out = String::new();
    for (region, (net, orders, refunds)) in groups {
        out.push_str(&format!("{}: net={}, orders={}, refunds={}\n", region, net, orders, refunds));
    }
    out
}

