pub enum Status {
    Draft,
    InReview,
    Approved,
    Published,
    Rejected,
    Archived,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Document {
    pub status: Status,
    pub revisions: u32,
    pub review_rounds: u32,
    pub approvals: u32,
    pub published_version: Option<u32>,
}

impl Document {
    pub fn new() -> Self {
        Self {
            status: Status::Draft,
            revisions: 0,
            review_rounds: 0,
            approvals: 0,
            published_version: None,
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Edit,
    Submit,
    Approve,
    Reject,
    Publish,
    Archive,
    Restore,
}

pub fn apply_event(doc: &mut Document, event: Event) {
    match event {
        Event::Edit => {
            doc.revisions += 1;
            doc.status = Status::Draft;
            doc.approvals = 0;
        }
        Event::Submit => {
            doc.status = Status::InReview;
        }
        Event::Approve => {
            doc.approvals += 1;
            doc.status = Status::Approved;
        }
        Event::Reject => {
            doc.status = Status::Rejected;
        }
        Event::Publish => {
            doc.status = Status::Published;
            doc.published_version = Some(doc.revisions);
        }
        Event::Archive => {
            doc.status = Status::Archived;
        }
        Event::Restore => {
            doc.status = Status::Draft;
        }
    }
}

