        let entry = totals.entry(sale.region).or_insert(0);
        *entry += sale.amount;

        let month_entry = months.entry(sale.region).or_insert(0);
        *month_entry += 1;
    }

    let mut out = Vec::new();
    for (region, total) in totals {
        let count = months.get(region).copied().unwrap_or(0);
        out.push(format!("{}: total={}, months={}", region, total, count));
