pub struct Metrics {
    pub ids: Vec<String>,
    pub total_score: i32,
    pub flagged_count: usize,
}

pub fn collect_metrics(lines: &[&str]) -> Metrics {
    let parsed: Vec<(&str, i32, bool)> = lines
        .iter()
        .filter_map(|line| {
            let mut parts = line.split('|');
            let id = parts.next()?;
            let score = parts.next()?.parse::<i32>().ok()?;
            let status = parts.next()?;
            Some((id, score, status == "flag"))
        })
        .collect();

    let ids = parsed
        .iter()
        .filter(|(_, score, _)| *score >= 0)
        .map(|(id, _, _)| id.to_string())
        .collect();

    let total_score = parsed
        .iter()
        .filter(|(_, score, _)| *score >= 0)
        .map(|(_, score, _)| *score)
        .sum();

    let flagged_count = parsed.iter().filter(|(_, _, flagged)| *flagged).count();

    Metrics {
        ids,
        total_score,
        flagged_count,
    }
}

