    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    New,
    InProgress,
    Blocked,
    Done,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Complete,
    Reopen,
    Close,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::New;
    let mut was_done = false;

    for event in events {
        match (*event, status) {
            (Event::Start, Status::New) => status = Status::InProgress,
            (Event::Start, Status::Blocked) => status = Status::InProgress,
            (Event::Block, Status::InProgress) => status = Status::Blocked,
            (Event::Unblock, Status::Blocked) => status = Status::New,
            (Event::Complete, Status::InProgress) => {
                status = Status::Done;
                was_done = true;
            }
            (Event::Reopen, Status::Done) => status = Status::New,
            (Event::Reopen, Status::Closed) => status = Status::New,
            (Event::Close, Status::Done) => status = Status::Closed,
            (Event::Close, Status::Blocked) if was_done => status = Status::Closed,
            _ => {}
        }
    }

    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event::*, Status};

    #[test]
    fn progress_path_can_close_after_completion() {
        let events = [Start, Complete, Close];
        assert_eq!(apply_events(&events), Status::Closed);
    }

    #[test]
    fn unblock_returns_to_in_progress() {
        let events = [Start, Block, Unblock];
        assert_eq!(apply_events(&events), Status::InProgress);
