    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum State {
    New,
    InProgress,
    Blocked,
    Done,
    Canceled,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Block,
    Unblock,
    Complete,
    Cancel,
    Reopen,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ticket {
    state: State,
    block_count: u32,
    was_completed: bool,
}

impl Ticket {
    pub fn new() -> Self {
        Self {
            state: State::New,
            block_count: 0,
            was_completed: false,
        }
    }

    pub fn state(&self) -> State {
        self.state
    }

    pub fn block_count(&self) -> u32 {
        self.block_count
    }

    pub fn was_completed(&self) -> bool {
        self.was_completed
    }

    pub fn apply(&mut self, event: Event) -> bool {
        match (self.state, event) {
            (State::New, Event::Start) => {
                self.state = State::InProgress;
                true
            }
            (State::New, Event::Cancel) => {
                self.state = State::Canceled;
                true
            }
            (State::InProgress, Event::Complete) => {
                self.state = State::Done;
                true
            }
            (State::InProgress, Event::Block) => {
                self.state = State::Blocked;
                true
            }
            (State::Blocked, Event::Unblock) => {
                self.state = State::InProgress;
                true
            }
            (State::Blocked, Event::Cancel) => {
                self.state = State::Canceled;
                true
            }
            (State::Done, Event::Reopen) => {
                self.state = State::New;
                true
            }
            _ => false,
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn complete_marks_done_and_history() {
        let mut t = Ticket::new();
        assert!(t.apply(Event::Start));
        assert!(t.apply(Event::Complete));
        assert_eq!(t.state(), State::Done);
        assert!(t.was_completed());
    }

    #[test]
    fn block_counts_each_entry_into_blocked() {
        let mut t = Ticket::new();
        assert!(t.apply(Event::Start));
        assert!(t.apply(Event::Block));
        assert_eq!(t.state(), State::Blocked);
        assert_eq!(t.block_count(), 1);
        assert!(t.apply(Event::Unblock));
        assert!(t.apply(Event::Block));
        assert_eq!(t.block_count(), 2);
    }

    #[test]
    fn reopen_from_done_goes_to_in_progress_if_previously_started() {
        let mut t = Ticket::new();
        assert!(t.apply(Event::Start));
        assert!(t.apply(Event::Complete));
        assert!(t.apply(Event::Reopen));
        assert_eq!(t.state(), State::InProgress);
    }

    #[test]
    fn cancel_is_allowed_while_in_progress() {
        let mut t = Ticket::new();
        assert!(t.apply(Event::Start));
        assert!(t.apply(Event::Cancel));
        assert_eq!(t.state(), State::Canceled);
    }

    #[test]
    fn cannot_reopen_canceled_ticket() {
        let mut t = Ticket::new();
        assert!(t.apply(Event::Cancel));
        assert!(!t.apply(Event::Reopen));
        assert_eq!(t.state(), State::Canceled);
    }
}
