pub struct Config {
    pub endpoint: String,
    pub retries: u8,
    pub timeout_ms: u32,
    pub headers: Vec<(String, String)>,
    pub features: Vec<String>,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub endpoint: Option<String>,
    pub retries: Option<u8>,
    pub timeout_ms: Option<u32>,
    pub headers: Vec<(String, String)>,
    pub features: Vec<String>,
}

pub fn merge_config(
    defaults: &Config,
    file: Option<&PartialConfig>,
    env: Option<&PartialConfig>,
    cli: Option<&PartialConfig>,
) -> Config {
    let mut merged = defaults.clone();

    for layer in [file, env, cli] {
        if let Some(layer) = layer {
            if let Some(endpoint) = &layer.endpoint {
                merged.endpoint = endpoint.clone();
            }
            if let Some(retries) = layer.retries {
                merged.retries = retries;
            }
            if let Some(timeout_ms) = layer.timeout_ms {
                merged.timeout_ms = timeout_ms;
            }
            if !layer.headers.is_empty() {
                merged.headers.extend(layer.headers.clone());
            }
            if !layer.features.is_empty() {
                merged.features = layer.features.clone();
            }
        }
    }

    merged
}

