    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Record {
    pub id: u32,
    pub name: String,
    pub active: bool,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();

    for block in input.split("\n\n") {
        if block.trim().is_empty() {
            continue;
        }

        let mut id = 0u32;
        let mut name = String::new();
        let mut active = false;

        for line in block.lines() {
            let line = line.trim();
            if line.is_empty() {
                continue;
            }

            let (key, value) = line
                .split_once(':')
                .ok_or_else(|| format!("invalid line: {}", line))?;

            match key.trim() {
                "id" => {
                    id = value.trim().parse().unwrap_or(0);
                }
                "name" => {
                    name = value.trim().to_string();
                }
                "active" => match value.trim() {
                    "true" => active = true,
                    "false" => active = false,
                    _ => return Err(format!("invalid active value: {}", value.trim())),
                },
                _ => return Err(format!("unknown field: {}", key.trim())),
            }
        }

        out.push(Record { id, name, active });
    }

    Ok(out)
}

