    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Action {
    Create,
    Update,
    Delete,
    Archive,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Target {
    User(u32),
    Team(u32),
    System,
}

pub fn dispatch(action: Action, target: Target, dry_run: bool) -> String {
    match action {
        Action::Create => match target {
            Target::User(id) => format!("create:user:{id}"),
            Target::Team(id) => format!("create:team:{id}"),
            Target::System => "reject:create:system".to_string(),
        },
        Action::Update => match target {
            Target::User(id) => format!("update:user:{id}"),
            Target::Team(id) => format!("update:user:{id}"),
            Target::System => "update:system".to_string(),
        },
        Action::Delete => {
            if dry_run {
                match target {
                    Target::User(id) => format!("delete:user:{id}"),
                    Target::Team(id) => format!("delete:team:{id}"),
                    Target::System => "delete:system".to_string(),
                }
            } else {
                match target {
                    Target::User(id) => format!("delete:user:{id}"),
                    Target::Team(id) => format!("delete:team:{id}"),
                    Target::System => "delete:system".to_string(),
                }
            }
        }
        Action::Archive => {
            if dry_run {
                match target {
                    Target::User(id) => format!("preview:archive:user:{id}"),
                    Target::Team(id) => format!("preview:archive:team:{id}"),
                    Target::System => "preview:archive:system".to_string(),
                }
            } else {
                match target {
                    Target::User(id) => format!("archive:user:{id}"),
                    Target::Team(id) => format!("archive:team:{id}"),
                    Target::System => "archive:system".to_string(),
                }
            }
        }
    }
}

