    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Record {
    pub id: u32,
    pub name: String,
    pub active: bool,
    pub tags: Vec<String>,
}

pub fn parse_record(input: &str) -> Result<Record, String> {
    let mut id = None;
    let mut name = None;
    let mut active = None;
    let mut tags = None;

    for part in input.split(';') {
        if part.is_empty() {
            continue;
        }
        let (key, value) = part
            .split_once('=')
            .ok_or_else(|| format!("bad field: {part}"))?;
        match key {
            "id" => {
                id = Some(value.parse::<u32>().map_err(|_| "invalid id".to_string())?);
            }
            "name" => {
                name = Some(value.to_string());
            }
            "active" => {
                active = Some(match value {
                    "true" => true,
                    "false" => false,
                    _ => return Err("invalid active".to_string()),
                });
            }
            "tags" => {
                let values = if value.is_empty() {
                    Vec::new()
                } else {
                    value.split(',').map(|s| s.to_string()).collect()
                };
                tags = Some(values);
            }
            _ => {}
        }
    }

    let record = Record {
        id: id.ok_or_else(|| "missing id".to_string())?,
        name: name.ok_or_else(|| "missing name".to_string())?,
        active: active.ok_or_else(|| "missing active".to_string())?,
        tags: tags.unwrap_or_default(),
    };

    if record.name.is_empty() {
        return Err("empty name".to_string());
    }

    Ok(record)
}

