        if name.is_empty() {
            return Err(format!("line {}: empty name", idx + 1));
        }

        let qty: u32 = qty.parse().map_err(|_| format!("line {}: invalid qty", idx + 1))?;
        out.push((name.to_string(), qty));
    }
    Ok(out)
