pub enum Status {
    New,
    InProgress,
    Blocked,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    StartWork,
    Block,
    Unblock,
    Resolve,
    Reopen,
    Close,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::New;
    let mut ever_started = false;

    for event in events {
        match event {
            Event::StartWork => {
                status = Status::InProgress;
                ever_started = true;
            }
            Event::Block => {
                status = Status::Blocked;
            }
            Event::Unblock => {
                status = Status::InProgress;
            }
            Event::Resolve => {
                status = Status::Resolved;
            }
            Event::Reopen => {
                status = Status::InProgress;
            }
            Event::Close => {
                if ever_started {
                    status = Status::Closed;
                }
            }
        }
    }

    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event, Status};

    #[test]
    fn close_requires_resolution() {
        let events = [Event::StartWork, Event::Close];
        assert_eq!(apply_events(&events), Status::InProgress);
    }

    #[test]
    fn reopen_from_closed_returns_resolved() {
        let events = [
            Event::StartWork,
            Event::Resolve,
            Event::Close,
            Event::Reopen,
        ];
        assert_eq!(apply_events(&events), Status::Resolved);
    }

    #[test]
    fn unblock_without_block_keeps_current_state() {
        let events = [Event::StartWork, Event::Unblock, Event::Resolve];
        assert_eq!(apply_events(&events), Status::Resolved);

        let events = [Event::New, Event::Unblock];
        let _ = events;
    }

    #[test]
    fn blocked_ticket_cannot_resolve_until_unblocked() {
        let events = [Event::StartWork, Event::Block, Event::Resolve, Event::Unblock];
        assert_eq!(apply_events(&events), Status::InProgress);
    }

    #[test]
    fn close_after_reopen_still_requires_resolve_again() {
        let events = [
            Event::StartWork,
            Event::Resolve,
            Event::Close,
            Event::Reopen,
            Event::Close,
        ];
        assert_eq!(apply_events(&events), Status::Resolved);
    }

    #[test]
    fn no_work_started_cannot_transition_with_progress_events() {
        let events = [Event::Block, Event::Resolve, Event::Close];
        assert_eq!(apply_events(&events), Status::New);
    }
}
