    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Connect { secure: bool },
    Message { urgent: bool, encrypted: bool },
    Disconnect { code: u16 },
    Tick,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Action {
    OpenChannel,
    OpenSecureChannel,
    Queue,
    DeliverFast,
    DeliverSecure,
    Retry,
    Close,
    Ignore,
}

pub fn decide(event: Event) -> Action {
    match event {
        Event::Connect { secure } => {
            if secure {
                Action::OpenChannel
            } else {
                Action::OpenChannel
            }
        }
        Event::Message { urgent, encrypted } => {
            if urgent {
                Action::DeliverFast
            } else if encrypted {
                Action::Queue
            } else {
                Action::Queue
            }
        }
        Event::Disconnect { code } => {
            if code >= 500 {
                Action::Retry
            } else {
                Action::Ignore
