    let mut ordered = players.to_vec();
    ordered.sort_by(|a, b| {
        a.score
            .cmp(&b.score)
            .then_with(|| a.name.cmp(&b.name))
            .then_with(|| a.wins.cmp(&b.wins))
    });

    ordered
