pub struct Config {
    pub host: String,
    pub port: u16,
    pub use_tls: bool,
    pub timeout_ms: u64,
    pub retries: u8,
    pub profile: String,
    pub endpoint: String,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
    pub timeout_ms: Option<u64>,
    pub retries: Option<u8>,
    pub profile: Option<String>,
    pub endpoint: Option<String>,
}

pub fn merge_config(
    defaults: &PartialConfig,
    env: &PartialConfig,
    user: &PartialConfig,
    runtime: &PartialConfig,
) -> Config {
    let host = defaults
        .host
        .clone()
        .or_else(|| env.host.clone())
        .or_else(|| user.host.clone())
        .or_else(|| runtime.host.clone())
        .unwrap_or_else(|| "localhost".to_string());

    let port = defaults
        .port
        .or(env.port)
        .or(user.port)
        .or(runtime.port)
        .unwrap_or(80);

    let use_tls = defaults
        .use_tls
        .or(env.use_tls)
        .or(user.use_tls)
        .or(runtime.use_tls)
        .unwrap_or(false);

    let timeout_ms = defaults
        .timeout_ms
        .or(env.timeout_ms)
        .or(user.timeout_ms)
        .or(runtime.timeout_ms)
        .unwrap_or(1000);

    let retries = defaults
        .retries
        .or(env.retries)
        .or(user.retries)
        .or(runtime.retries)
        .unwrap_or(3);

    let profile = defaults
        .profile
        .clone()
        .or_else(|| env.profile.clone())
        .or_else(|| user.profile.clone())
        .or_else(|| runtime.profile.clone())
        .unwrap_or_else(|| "default".to_string());

    let endpoint = runtime
        .endpoint
        .clone()
        .or_else(|| user.endpoint.clone())
        .or_else(|| env.endpoint.clone())
        .or_else(|| defaults.endpoint.clone())
        .unwrap_or_else(|| {
            let scheme = if use_tls { "https" } else { "http" };
            format!("{}://{}:{}", scheme, host, port)
        });

    Config {
        host,
        port,
        use_tls,
        timeout_ms,
        retries,
        profile,
        endpoint,
    }
}

