    pub points: i32,
    pub wins: u32,
    pub losses: u32,
}

pub fn rank_players(entries: &[Entry], limit: usize) -> Vec<String> {
    let mut merged: HashMap<String, Entry> = HashMap::new();

    for e in entries {
        let slot = merged.entry(e.player.clone()).or_insert_with(|| Entry {
            player: e.player.clone(),
            points: 0,
            wins: 0,
            losses: 0,
        });
        slot.points += e.points;
        slot.wins += e.wins;
        slot.losses += e.losses;
    }

    let mut items: Vec<Entry> = merged.into_values().collect();
    items.sort_by(|a, b| {
        a.points
            .cmp(&b.points)
            .then(a.wins.cmp(&b.wins))
            .then(a.losses.cmp(&b.losses))
            .then(a.player.cmp(&b.player))
    });

    items
        .into_iter()
        .take(limit)
        .map(|e| format!("{}:{}-{} ({})", e.player, e.wins, e.losses, e.points))
        .collect()
}

