    pub rep: &'static str,
    pub amount: i32,
    pub refunded: bool,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RegionSummary {
    pub region: String,
    pub net_total: i32,
    pub transactions: usize,
    pub unique_reps: usize,
    pub refunds: usize,
}

pub fn summarize_sales(sales: &[Sale], min_net_total: i32) -> Vec<RegionSummary> {
    let mut grouped: BTreeMap<&str, RegionSummary> = BTreeMap::new();

    for sale in sales {
        let entry = grouped.entry(sale.region).or_insert_with(|| RegionSummary {
            region: sale.region.to_string(),
            net_total: 0,
            transactions: 0,
            unique_reps: 0,
            refunds: 0,
