        entry.net_total += sale.amount;
        entry.transactions += 1;
        if sale.refunded {
            entry.refunds += 1;
        }
    }

    let mut out: Vec<RegionSummary> = grouped
        .into_values()
        .filter(|s| s.net_total > min_net_total)
        .collect();

    out.sort_by(|a, b| a.region.cmp(&b.region));
    out
}

