    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Draft,
    Submitted,
    Approved,
    Rejected,
    Published,
    Archived,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Reject,
    Revise,
    Publish,
    Archive,
    Restore,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ticket {
    pub status: Status,
    pub revisions: u32,
    pub approvals: u32,
    pub rejection_reason: Option<String>,
    pub archived_from: Option<Status>,
}

impl Ticket {
    pub fn new() -> Self {
        Self {
            status: Status::Draft,
            revisions: 0,
            approvals: 0,
            rejection_reason: None,
            archived_from: None,
        }
    }

    pub fn apply(&mut self, event: Event, reason: Option<&str>) -> bool {
        match event {
            Event::Submit => {
                self.status = Status::Submitted;
                true
            }
            Event::Approve => {
                self.approvals += 1;
                self.status = Status::Approved;
                true
            }
            Event::Reject => {
                self.status = Status::Rejected;
                self.rejection_reason = reason.map(|s| s.to_string());
                true
            }
            Event::Revise => {
                self.status = Status::Draft;
                true
            }
            Event::Publish => {
                self.status = Status::Published;
                true
            }
            Event::Archive => {
                self.archived_from = Some(self.status);
                self.status = Status::Archived;
                true
            }
            Event::Restore => {
                self.status = self.archived_from.unwrap_or(Status::Draft);
                true
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn submit_only_from_draft_and_clears_rejection_reason() {
        let mut t = Ticket::new();
        assert!(t.apply(Event::Reject, Some("missing data")));
        assert_eq!(t.status, Status::Rejected);
        assert_eq!(t.rejection_reason.as_deref(), Some("missing data"));

        assert!(!t.apply(Event::Submit, None));
        assert_eq!(t.status, Status::Rejected);

        assert!(t.apply(Event::Revise, None));
        assert_eq!(t.status, Status::Draft);
        assert_eq!(t.revisions, 1);

        assert!(t.apply(Event::Submit, None));
        assert_eq!(t.status, Status::Submitted);
        assert_eq!(t.rejection_reason, None);
    }

    #[test]
    fn approve_requires_submitted_and_publish_requires_approved() {
        let mut t = Ticket::new();
        assert!(!t.apply(Event::Approve, None));
        assert_eq!(t.approvals, 0);
        assert_eq!(t.status, Status::Draft);

        assert!(t.apply(Event::Submit, None));
        assert!(t.apply(Event::Approve, None));
        assert_eq!(t.approvals, 1);
        assert_eq!(t.status, Status::Approved);

        assert!(!t.apply(Event::Approve, None));
        assert_eq!(t.approvals, 1);

        let mut t2 = Ticket::new();
        assert!(t2.apply(Event::Submit, None));
        assert!(!t2.apply(Event::Publish, None));
        assert_eq!(t2.status, Status::Submitted);

        assert!(t.apply(Event::Publish, None));
        assert_eq!(t.status, Status::Published);
    }

    #[test]
    fn reject_requires_submitted_and_needs_non_empty_reason() {
        let mut t = Ticket::new();
        assert!(!t.apply(Event::Reject, Some("bad")));
        assert_eq!(t.status, Status::Draft);

        assert!(t.apply(Event::Submit, None));
        assert!(!t.apply(Event::Reject, None));
        assert_eq!(t.status, Status::Submitted);
        assert!(!t.apply(Event::Reject, Some("")));
        assert_eq!(t.status, Status::Submitted);

        assert!(t.apply(Event::Reject, Some("policy")));
        assert_eq!(t.status, Status::Rejected);
        assert_eq!(t.rejection_reason.as_deref(), Some("policy"));
    }

    #[test]
    fn revise_only_from_rejected_increments_count_and_resets_approvals() {
        let mut t = Ticket::new();
        assert!(!t.apply(Event::Revise, None));
        assert_eq!(t.status, Status::Draft);
