    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Event {
    Open,
    Resolve,
    Reopen,
    Close,
}

fn apply_event(state: &str, event: Event) -> String {
    match event {
        Event::Open => "Open".to_string(),
        Event::Resolve => "Closed".to_string(),
        Event::Reopen => "Open".to_string(),
        Event::Close => "Closed".to_string(),
    }
}

fn main() {
    let events = [
        ("A", Event::Open),
        ("A", Event::Resolve),
        ("A", Event::Close),
        ("B", Event::Open),
        ("B", Event::Resolve),
        ("B", Event::Reopen),
        ("C", Event::Open),
        ("C", Event::Resolve),
    ];

    let mut states: BTreeMap<&str, String> = BTreeMap::new();

    for (ticket, event) in events {
        let current = states.get(ticket).map(String::as_str).unwrap_or("New");
        let next = apply_event(current, event);
        states.insert(ticket, next);
    }

    for (ticket, state) in states {
        println!("{}: {}", ticket, state);
    }
}
