        (Action::Copy { dst, .. }, _) | (Action::Move { dst, .. }, _) if dst.is_empty() => {
            "blocked(missing dst)".to_string()
        }
        (Action::Archive { items, .. }, _) if *items == 0 => "blocked(empty archive)".to_string(),
        _ => "ready".to_string(),
