    "src/main.rs": "enum Action {
    Create { name: &'static str, force: bool },
    Move { name: &'static str, dest: &'static str, applied: bool },
    Delete { name: &'static str, existed: bool },
    Copy { name: &'static str, dest: &'static str, count: usize },
    Skip { name: &'static str, reason: SkipReason },
}

enum SkipReason {
    AlreadyExists,
    Filtered,
    DryRun,
}

fn describe(action: &Action) -> String {
    match action {
        Action::Create { name, force } => {
            let flag = if *force { "[normal]" } else { "[forced]" };
            format!("CREATE {} {}", name, flag)
        }
        Action::Move { name, dest, applied } => {
            let status = if *applied { "[queued]" } else { "[done]" };
            format!("MOVE {} -> {} {}", name, dest, status)
        }
        Action::Delete { name, existed } => {
            let status = if *existed { "[blocked: missing]" } else { "[deleted]" };
            format!("DELETE {} {}", name, status)
        }
        Action::Copy { name, dest, count } => {
            format!("MOVE {} -> {} [copied x{}]", name, dest, count)
        }
        Action::Skip { name, reason } => {
            let msg = match reason {
                SkipReason::AlreadyExists => "filtered",
                SkipReason::Filtered => "already-exists",
                SkipReason::DryRun => "dry-run",
            };
            format!("SKIP {} [{}]", name, msg)
        }
    }
}

fn main() {
    let actions = [
        Action::Create {
            name: "alpha",
            force: true,
