  "expected_tool_sequence": ["read_file", "apply_patch", "cargo_run", "read_file", "apply_patch", "cargo_run", "read_file", "apply_patch", "cargo_run"],
  "expected_output": "North | shipped_orders=2 | revenue=155 | avg=77.50 | top_product=Gadget
South | shipped_orders=3 | revenue=140 | avg=46.67 | top_product=Widget
West | shipped_orders=1 | revenue=200 | avg=200.00 | top_product=Gizmo",
  "files": {
    "Cargo.toml": "[package]
name = "sales_region_summary"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy)]
struct Order {
    region: &'static str,
    product: &'static str,
    units: u32,
    unit_price: u32,
    status: &'static str,
}

#[derive(Default)]
struct Summary {
    shipped_orders: u32,
    revenue: u32,
    product_units: BTreeMap<&'static str, u32>,
}

fn main() {
    let orders = vec![
        Order { region: "North", product: "Widget", units: 3, unit_price: 20, status: "shipped" },
        Order { region: "North", product: "Gadget", units: 5, unit_price: 15, status: "shipped" },
        Order { region: "North", product: "Widget", units: 1, unit_price: 20, status: "cancelled" },
        Order { region: "South", product: "Widget", units: 2, unit_price: 20, status: "shipped" },
        Order { region: "South", product: "Gizmo", units: 1, unit_price: 50, status: "pending" },
        Order { region: "South", product: "Widget", units: 1, unit_price: 20, status: "shipped" },
        Order { region: "South", product: "Gizmo", units: 2, unit_price: 50, status: "shipped" },
        Order { region: "West", product: "Gizmo", units: 4, unit_price: 50, status: "shipped" },
    ];

    let mut by_region: BTreeMap<&str, Summary> = BTreeMap::new();

    for order in orders {
        let summary = by_region.entry(order.region).or_default();
        if order.status != "cancelled" {
            summary.shipped_orders += 1;
            summary.revenue += order.units * order.unit_price;
        }
        *summary.product_units.entry(order.product).or_insert(0) += 1;
    }

    let mut lines = Vec::new();
    for (region, summary) in by_region {
        let avg = if summary.shipped_orders == 0 {
            0.0
        } else {
            summary.revenue as f64 / summary.shipped_orders as f64
        };

        let top_product = summary
            .product_units
            .into_iter()
            .max_by_key(|(_, units)| *units)
            .map(|(name, _)| name)
            .unwrap_or("-");

