    "src/main.rs": "enum Event {
    Create,
    Start,
    Resolve,
    Reopen,
    Close,
}

#[derive(Clone, Copy)]
enum Status {
    New,
    InProgress,
    Resolved,
    Reopened,
    Closed,
}

impl Status {
    fn label(self) -> &'static str {
        match self {
            Status::New => "New",
            Status::InProgress => "InProgress",
            Status::Resolved => "Resolved",
            Status::Reopened => "Reopened",
            Status::Closed => "Closed",
        }
    }
}

fn apply(mut status: Status, event: Event) -> Status {
    match event {
        Event::Create => status = Status::New,
        Event::Start => status = Status::InProgress,
        Event::Resolve => status = Status::Resolved,
        Event::Reopen => status = Status::New,
        Event::Close => status = Status::Resolved,
    }
    status
}

fn run(events: &[Event]) -> Status {
    let mut status = Status::New;
    for event in events {
        status = apply(status, match event {
            Event::Create => Event::Create,
            Event::Start => Event::Start,
            Event::Resolve => Event::Resolve,
            Event::Reopen => Event::Reopen,
            Event::Close => Event::Close,
        });
    }
    status
}

fn main() {
