        ("T1", vec![Event::Create, Event::Start, Event::Resolve, Event::Close]),
        ("T2", vec![Event::Create, Event::Start, Event::Resolve, Event::Reopen]),
        ("T3", vec![Event::Create, Event::Close]),
    ];

    for (id, events) in tickets {
        let status = run(&events);
        println!("{}:{}", id, status.label());
    }
}
