    "src/main.rs": "use std::collections::BTreeMap;

fn apply_event(state: &str, event: &str) -> String {
    match (state, event) {
        ("new", "start") => "in_progress".to_string(),
        ("in_progress", "resolve") => "closed".to_string(),
        ("closed", "reopen") => "new".to_string(),
        _ => state.to_string(),
    }
}

fn main() {
    let events = [
        ("A", "start"),
        ("A", "resolve"),
        ("B", "start"),
        ("C", "start"),
        ("C", "resolve"),
        ("C", "reopen"),
        ("C", "start"),
        ("C", "resolve"),
    ];

    let mut states: BTreeMap<&str, String> = BTreeMap::new();

    for (ticket, event) in events {
        let current = states.get(ticket).map(|s| s.as_str()).unwrap_or("new");
        let next = apply_event(current, event);
        states.insert(ticket, next);
    }

    for (ticket, state) in states {
        println!("{}:{}", ticket, state);
    }
}
