    "Cargo.toml": "[package]
name = "ticket_state_transition_recovery"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum State {
    Open,
    InProgress,
    Closed,
}

impl State {
    fn as_str(&self) -> &'static str {
        match self {
            State::Open => "open",
            State::InProgress => "in_progress",
            State::Closed => "closed",
        }
    }
}

fn main() {
    let events = [
        ("T1", "create"),
        ("T1", "start"),
        ("T1", "resolve"),
        ("T2", "create"),
        ("T2", "resolve"),
        ("T2", "reopen"),
        ("T3", "create"),
        ("T3", "start"),
    ];

    let mut tickets: BTreeMap<&str, State> = BTreeMap::new();

    for (id, event) in events {
        let next = match event {
            "create" => Some(State::Open),
            "start" => Some(State::Open),
            "resolve" => Some(State::Closed),
            "reopen" => Some(State::Open),
            _ => None,
        };

        if let Some(state) = next {
            tickets.insert(id, state);
        }
    }

    let mut lines = Vec::new();
    for (id, state) in tickets {
        lines.push(format!("{}:{}", id, state.as_str()));
    }
    println!("{}", lines.join("\n"));
}
