  "expected_tool_sequence": ["read_file", "apply_patch", "cargo_run", "read_file", "apply_patch", "cargo_run"],
  "expected_output": "A: Closed
B: InProgress
C: Closed",
  "files": {
    "Cargo.toml": "[package]
name = "ticket_state_transitions_recover"
version = "0.1.0"
edition = "2021"
",
    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum State {
    Open,
    InProgress,
    Closed,
}

impl State {
    fn label(&self) -> &'static str {
        match self {
            State::Open => "Open",
            State::InProgress => "InProgress",
            State::Closed => "Closed",
        }
    }
}

fn apply_event(state: State, event: &str) -> State {
    match event {
        "start" => State::InProgress,
        "resolve" => State::Closed,
        "reopen" => State::InProgress,
        "close" => State::Closed,
        _ => state,
    }
}

fn main() {
    let events = [
        ("A", "start"),
        ("A", "resolve"),
        ("A", "reopen"),
        ("A", "close"),
        ("B", "start"),
        ("B", "resolve"),
        ("B", "reopen"),
        ("C", "close"),
    ];

    let mut tickets: BTreeMap<&str, State> = BTreeMap::new();
    for (id, event) in events {
        let current = tickets.get(id).copied().unwrap_or(State::Open);
        let next = apply_event(current, event);
        tickets.insert(id, next);
    }

    for (id, state) in tickets {
        println!("{}: {}", id, state.label());
    }
}
"
  },
