    "src/main.rs": "#[derive(Clone, Copy)]
enum Event {
    Create,
    Pay,
    Ship,
    Deliver,
    Cancel,
    Return,
}

#[derive(Clone, Copy)]
enum Status {
    New,
    Paid,
    Shipped,
    Delivered,
    Canceled,
    Returned,
}

fn apply(mut status: Option<Status>, event: Event) -> Option<Status> {
    use Event::*;
    use Status::*;

    status = match (status, event) {
        (None, Create) => Some(New),
        (Some(New), Pay) => Some(Paid),
        (Some(Paid), Ship) => Some(Shipped),
        (Some(Shipped), Deliver) => Some(Delivered),
        (_, Cancel) => Some(Canceled),
        (Some(Delivered), Return) => Some(Delivered),
        (s, _) => s,
    };

    status
}

fn label(status: Option<Status>) -> &'static str {
    match status {
        Some(Status::New) => "new",
        Some(Status::Paid) => "paid",
        Some(Status::Shipped) => "shipped",
        Some(Status::Delivered) => "done",
        Some(Status::Canceled) => "canceled",
        Some(Status::Returned) => "returned",
        None => "missing",
    }
}

