T3=in_progress, assignee=carol, comments=1, blocked=false",
  "files": {
    "Cargo.toml": "[package]
name = "ticket_state_timeline"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone)]
struct Ticket {
    status: &'static str,
    assignee: &'static str,
    comments: usize,
    blocked: bool,
}

enum Event {
    Open { id: &'static str },
    Assign { id: &'static str, user: &'static str },
    Comment { id: &'static str },
    Block { id: &'static str },
    Unblock { id: &'static str },
    Start { id: &'static str },
    Close { id: &'static str },
    Reopen { id: &'static str },
}

fn apply_event(ticket: &mut Ticket, event: &Event) {
    match event {
        Event::Open { .. } => {}
        Event::Assign { user, .. } => ticket.assignee = user,
        Event::Comment { .. } => {}
        Event::Block { .. } => ticket.blocked = false,
        Event::Unblock { .. } => ticket.blocked = false,
        Event::Start { .. } => {
            if ticket.status == "open" {
                ticket.status = "in_progress";
            }
        }
        Event::Close { .. } => ticket.status = "closed",
        Event::Reopen { .. } => ticket.status = "in_progress",
    }
}

fn id_of(event: &Event) -> &'static str {
    match event {
        Event::Open { id }
        | Event::Assign { id, .. }
        | Event::Comment { id }
        | Event::Block { id }
        | Event::Unblock { id }
        | Event::Start { id }
        | Event::Close { id }
        | Event::Reopen { id } => id,
    }
}

fn main() {
    let events = vec![
        Event::Open { id: "T1" },
        Event::Assign { id: "T1", user: "alice" },
        Event::Comment { id: "T1" },
        Event::Block { id: "T1" },
        Event::Comment { id: "T1" },
        Event::Unblock { id: "T1" },
        Event::Open { id: "T2" },
        Event::Assign { id: "T2", user: "bob" },
