#[derive(Clone, Debug)]
struct Ticket {
    state: State,
    owner: Option<&'static str>,
    history: Vec<State>,
}

impl Ticket {
    fn new() -> Self {
        Self {
            state: State::Open,
            owner: None,
            history: vec![State::Open],
        }
