edition = "2021"
",
    "src/main.rs": "use std::collections::{BTreeMap, BTreeSet};

#[derive(Clone, Copy, PartialEq, Eq)]
enum Status {
    Paid,
    Pending,
    Cancelled,
}

struct Order {
    region: &'static str,
    customer: &'static str,
    amount: i32,
    discount: i32,
    status: Status,
}

fn sample_orders() -> Vec<Order> {
    vec![
        Order { region: "North", customer: "alice", amount: 120, discount: 20, status: Status::Paid },
        Order { region: "North", customer: "bob", amount: 150, discount: 0, status: Status::Paid },
        Order { region: "North", customer: "alice", amount: 50, discount: 0, status: Status::Pending },
        Order { region: "South", customer: "cara", amount: 90, discount: 10, status: Status::Cancelled },
        Order { region: "South", customer: "dave", amount: 110, discount: 10, status: Status::Pending },
        Order { region: "East", customer: "erin", amount: 200, discount: 50, status: Status::Paid },
        Order { region: "East", customer: "frank", amount: 20, discount: 0, status: Status::Paid },
        Order { region: "West", customer: "gina", amount: 80, discount: 0, status: Status::Paid },
        Order { region: "West", customer: "harry", amount: 150, discount: 50, status: Status::Paid },
        Order { region: "West", customer: "gina", amount: 30, discount: 0, status: Status::Cancelled },
    ]
}

fn build_report(orders: &[Order]) -> String {
    let mut revenue_by_region: BTreeMap<&str, i32> = BTreeMap::new();
    let mut customers_by_region: BTreeMap<&str, BTreeSet<&str>> = BTreeMap::new();

    for order in orders {
        *revenue_by_region.entry(order.region).or_insert(0) += order.amount;
        customers_by_region
            .entry(order.region)
            .or_default()
            .insert(order.customer);
    }

    let mut rows: Vec<_> = revenue_by_region.into_iter().collect();
    rows.sort_by(|a, b| a.0.cmp(b.0));

    let mut out = String::new();
    let mut total_revenue = 0;
    let mut total_customers = 0;

    for (region, revenue) in rows {
        let customer_count = customers_by_region.get(region).map(|s| s.len()).unwrap_or(0);
        total_revenue += revenue;
        total_customers += customer_count;
        out.push_str(&format!("{} | revenue={} | customers={}\n", region, revenue, customer_count));
    }

    out.push_str(&format!("TOTAL | revenue={} | customers={}", total_revenue, total_customers));
    out
}

fn main() {
    print!("{}", build_report(&sample_orders()));
}
