#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    New,
    InProgress,
    Blocked,
    Closed,
    Cancelled,
}

impl Status {
    fn as_str(self) -> &'static str {
        match self {
            Status::New => "New",
            Status::InProgress => "InProgress",
            Status::Blocked => "Blocked",
            Status::Closed => "Closed",
            Status::Cancelled => "Cancelled",
        }
    }
}

#[derive(Clone, Copy)]
enum Event {
    Create,
    Start,
    Block,
    Resolve,
    Close,
    Cancel,
}

#[derive(Clone, Copy)]
struct Ticket {
    status: Status,
    history_len: usize,
}

fn apply_event(ticket: &mut Ticket, event: Event) {
    match event {
        Event::Create => {
            ticket.status = Status::New;
            ticket.history_len += 1;
        }
        Event::Start => {
            if ticket.status != Status::Closed {
                ticket.status = Status::InProgress;
                ticket.history_len += 1;
            }
        }
        Event::Block => {
            if ticket.status == Status::InProgress {
                ticket.status = Status::Blocked;
                ticket.history_len += 1;
            }
        }
        Event::Resolve => {
            if ticket.status == Status::Blocked {
                ticket.status = Status::InProgress;
            }
            ticket.history_len += 1;
        }
        Event::Close => {
            ticket.status = Status::Closed;
            ticket.history_len += 1;
        }
        Event::Cancel => {
            if ticket.status != Status::Closed {
                ticket.status = Status::Cancelled;
            }
            ticket.history_len += 1;
        }
    }
}

