fn is_valid_record(line: &str) -> bool {
    let mut parts = line.split(';');
    let id = parts.next();
    let qty = parts.next();

    if parts.next().is_some() {
        return false;
    }

    match (id, qty) {
        (Some(id), Some(qty)) => !id.is_empty() && qty.parse::<u32>().is_ok(),
        _ => false,
    }
}

