pub struct Config {
    pub mode: String,
    pub retries: u8,
    pub verbose: bool,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub mode: Option<String>,
    pub retries: Option<u8>,
    pub verbose: Option<bool>,
}

impl PartialConfig {
    fn apply_over(self, mut base: Config) -> Config {
        if let Some(mode) = self.mode {
            base.mode = mode;
        }
        if let Some(retries) = self.retries {
            base.retries = retries;
        }
        if self.verbose.unwrap_or(false) {
            base.verbose = true;
        }
        base
    }
}

pub fn merge_config(
    defaults: Config,
    env: PartialConfig,
    profile: PartialConfig,
    cli: PartialConfig,
) -> Config {
    let merged = profile.apply_over(defaults);
    let merged = env.apply_over(merged);
    cli.apply_over(merged)
}

#[cfg(test)]
mod tests {
    use super::*;

    fn defaults() -> Config {
        Config {
            mode: "safe".to_string(),
            retries: 2,
            verbose: true,
