        let profile = PartialConfig {
            mode: None,
            retries: None,
            verbose: Some(true),
        };
        let cli = PartialConfig {
            mode: None,
            retries: None,
            verbose: Some(false),
        };

        let merged = merge_config(defaults(), env, profile, cli);
        assert!(!merged.verbose);
    }

