pub fn parse_record(line: &str) -> Option<Record> {
    let parts: Vec<&str> = line.split('|').collect();
    if parts.len() < 3 {
        return None;
    }

    let id = parts[0].parse().ok()?;
    let name = parts[1];
    if name.is_empty() {
        return None;
    }

    let active = match parts[2] {
        "true" => true,
        "false" => false,
        _ => return None,
