#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Pause,
    Resume,
    Resolve,
    Close,
    Reopen,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::Open;

    for event in events {
        status = match (status, *event) {
            (Status::Open, Event::Start) => Status::InProgress,
            (Status::InProgress, Event::Pause) => Status::OnHold,
            (Status::OnHold, Event::Resume) => Status::Open,
            (_, Event::Resolve) => Status::Resolved,
            (Status::Resolved, Event::Close) => Status::Closed,
            (_, Event::Reopen) => Status::Open,
            (current, _) => current,
        };
    }

    status
}

