    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Status {
    New,
    InProgress,
    Blocked,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Event {
    StartWork,
    Block,
    Unblock,
    Resolve,
    Close,
    Reopen,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ticket {
    pub status: Status,
    pub resolution: Option<&'static str>,
    pub reopen_count: u8,
}

impl Ticket {
    pub fn new() -> Self {
        Self {
            status: Status::New,
            resolution: None,
            reopen_count: 0,
        }
    }

    pub fn apply(&mut self, event: Event) {
        match event {
            Event::StartWork => {
                if matches!(self.status, Status::New) {
                    self.status = Status::InProgress;
                }
            }
            Event::Block => {
                if matches!(self.status, Status::InProgress) {
                    self.status = Status::Blocked;
                }
            }
            Event::Unblock => {
                if matches!(self.status, Status::Blocked) {
                    self.status = Status::InProgress;
                }
            }
            Event::Resolve => {
                if matches!(self.status, Status::InProgress | Status::Blocked) {
                    self.status = Status::Resolved;
                    self.resolution = Some("done");
                }
            }
            Event::Close => {
                if matches!(self.status, Status::Resolved) {
                    self.status = Status::Closed;
                }
            }
            Event::Reopen => {
                if matches!(self.status, Status::Resolved | Status::Closed) {
                    self.status = Status::InProgress;
                }
            }
        }
    }
}

pub fn apply_events(events: &[Event]) -> Ticket {
    let mut ticket = Ticket::new();
    for event in events.iter().cloned() {
        ticket.apply(event);
    }
    ticket
}

