pub fn apply_events(events: &[Event]) -> Ticket {
    let mut ticket = Ticket {
        state: TicketState::New,
        assignee: None,
        resolution: None,
    };

    for event in events {
        match *event {
            Event::Assign(name) => {
                ticket.assignee = Some(name.to_string());
