            if ticket.status != Status::Closed && ticket.blockers == 0 {
                ticket.status = Status::InProgress;
            }
        }
        Event::Block(_) => {
            ticket.blockers += 1;
            ticket.status = Status::Blocked;
        }
        Event::Unblock(_) => {
            if ticket.blockers > 0 {
