    a.start <= b.end && b.start <= a.end
}

fn main() {
    let bookings = vec![
        Booking { room: "A", start: 540, end: 600, label: "standup" },
        Booking { room: "A", start: 600, end: 630, label: "retro" },
        Booking { room: "A", start: 615, end: 660, label: "planning" },
        Booking { room: "A", start: 650, end: 690, label: "interview" },
        Booking { room: "B", start: 480, end: 510, label: "support" },
        Booking { room: "C", start: 700, end: 720, label: "solo" },
        Booking { room: "C", start: 720, end: 780, label: "pairing" },
        Booking { room: "D", start: 900, end: 930, label: "wrapup" },
        Booking { room: "D", start: 925, end: 940, label: "handoff" },
    ];

    let mut by_room: BTreeMap<&str, Vec<Booking>> = BTreeMap::new();
    for b in bookings {
        by_room.entry(b.room).or_default().push(b);
    }

    let mut lines = Vec::new();
    for (room, items) in by_room {
        let mut conflicts = Vec::new();
        for i in 0..items.len() {
            for j in (i + 1)..items.len() {
                if overlaps(&items[i], &items[j]) {
                    conflicts.push(format!("{}&{}", items[i].label, items[j].label));
                }
            }
        }

        if conflicts.is_empty() {
            let labels = items.iter().map(|b| b.label).collect::<Vec<_>>().join(", ");
            lines.push(format!("Room {}: ok [{}]", room, labels));
        } else {
            lines.push(format!("Room {}: CONFLICTS [{}]", room, conflicts.join(", ")));
        }
    }

    println!("{}", lines.join("\n"));
}
