fn apply(ticket: &mut Ticket, event: Event) {
    match event {
        Event::Assign(name) => ticket.owner = name,
        Event::Start => ticket.state = State::InProgress,
        Event::Block => ticket.state = State::Blocked,
        Event::Resume => ticket.state = State::InProgress,
        Event::Resolve => ticket.state = State::Resolved,
        Event::Close => ticket.state = State::Closed,
