{
  "family": "run_only",
  "case_id": "ticket_state_transition_audit_report",
  "bug_category": "state_transitions",
  "difficulty": "medium",
  "user": "Run the Rust crate at {project_root} and report the program output exactly.",
  "expected_tool_sequence": ["cargo_run"],
  "expected_output": "A1 open -> in_progress -> blocked -> in_progress -> done | final=done reopened=1 blocked=1 invalid=0
B2 open -> blocked -> done | final=blocked reopened=0 blocked=1 invalid=1
C3 open -> done -> open -> in_progress -> done | final=done reopened=1 blocked=0 invalid=0
SUMMARY done=2 blocked=1 open=0 invalid_events=1",
  "files": {
    "Cargo.toml": "[package]
name = "ticket_state_transition_audit_report"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy, PartialEq, Eq)]
enum Status {
    Open,
    InProgress,
    Blocked,
    Done,
}

impl Status {
    fn as_str(self) -> &'static str {
        match self {
            Status::Open => "open",
            Status::InProgress => "in_progress",
            Status::Blocked => "blocked",
            Status::Done => "done",
        }
    }
}

enum Event {
    Start,
    Block,
    Unblock,
    Finish,
    Reopen,
}

struct TicketReport {
    id: &'static str,
    history: Vec<Status>,
    final_status: Status,
    reopened: usize,
    blocked_count: usize,
    invalid: usize,
}

fn apply_event(status: Status, event: Event) -> Option<Status> {
    match (status, event) {
        (Status::Open, Event::Start) => Some(Status::InProgress),
        (Status::Open, Event::Block) => Some(Status::Blocked),
        (Status::Open, Event::Finish) => Some(Status::Done),
        (Status::InProgress, Event::Block) => Some(Status::Blocked),
        (Status::InProgress, Event::Finish) => Some(Status::Done),
        (Status::Blocked, Event::Unblock) => Some(Status::InProgress),
        (Status::Blocked, Event::Finish) => Some(Status::Done),
        (Status::Done, Event::Reopen) => Some(Status::Open),
        _ => None,
    }
}

fn process(id: &'static str, events: &[Event]) -> TicketReport {
    let mut status = Status::Open;
    let mut history = vec![status];
    let mut reopened = 0;
    let mut blocked_count = 0;
    let mut invalid = 0;

    for event in events {
        match event {
            Event::Block => blocked_count += 1,
            Event::Reopen => {
                if status == Status::Done {
                    reopened += 1;
                }
            }
            _ => {}
        }

        if let Some(next) = apply_event(status, match event {
            Event::Start => Event::Start,
            Event::Block => Event::Block,
            Event::Unblock => Event::Unblock,
            Event::Finish => Event::Finish,
            Event::Reopen => Event::Reopen,
        }) {
            status = next;
            history.push(status);
        } else {
            invalid += 1;
        }
    }

    TicketReport {
        id,
        history,
        final_status: status,
        reopened,
        blocked_count,
        invalid,
    }
}

fn main() {
    let reports = vec![
        process(
            "A1",
            &[
                Event::Start,
                Event::Block,
                Event::Unblock,
                Event::Finish,
                Event::Reopen,
                Event::Start,
                Event::Finish,
            ],
        ),
        process("B2", &[Event::Block, Event::Finish]),
        process(
            "C3",
            &[
                Event::Finish,
                Event::Reopen,
                Event::Start,
                Event::Finish,
            ],
        ),
    ];

    let mut counts: BTreeMap<&'static str, usize> = BTreeMap::new();
    let mut invalid_total = 0;

    for report in &reports {
        let key = report.final_status.as_str();
        *counts.entry(key).or_insert(0) += 1;
        invalid_total += report.invalid;

        let path = report
            .history
            .iter()
            .map(|s| s.as_str())
            .collect::<Vec<_>>()
            .join(" -> ");

        println!(
            "{} {} | final={} reopened={} blocked={} invalid={}",
            report.id,
            path,
            report.final_status.as_str(),
            report.reopened,
            report.blocked_count,
            report.invalid
        );
    }

    println!(
        "SUMMARY done={} blocked={} open={} invalid_events={}",
        counts.get("done").copied().unwrap_or(0),
        counts.get("blocked").copied().unwrap_or(0),
        counts.get("open").copied().unwrap_or(0),
        invalid_total
    );
}
"
  },
  "steps": [
    {
      "tool": "cargo_run",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: A1 open -> in_progress -> blocked -> in_progress -> done | final=done reopened=1 blocked=1 invalid=0
B2 open -> blocked -> done | final=blocked reopened=0 blocked=1 invalid=1
C3 open -> done -> open -> in_progress -> done | final=done reopened=1 blocked=0 invalid=0
SUMMARY done=2 blocked=1 open=0 invalid_events=1"
}

