            action: Action::Lock {
                locked: true,
                jammed: true,
            },
        },
        Event {
            name: "sensor",
            kind: DeviceKind::Sensor,
            action: Action::Fault(Some("offline")),
        },
    ];

    for (i, event) in events.iter().enumerate() {
        if i > 0 {
            println!();
        }
        print!("{}", describe(event));
    }
